using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(TicketClassifierService classifierService) : ControllerBase
{
    [HttpPost("train")]
    public IActionResult Train()
    {
        classifierService.Train();
        return Ok(new { message = "Model trained successfully." });
    }

    [HttpGet("evaluate")]
    public IActionResult Evaluate()
    {
        if (!classifierService.IsTrained)
            return BadRequest(new { error = "Model has not been trained yet. Call POST /api/ticketclassifier/train first." });

        var result = classifierService.Evaluate();
        return Ok(result);
    }

    [HttpPost("predict")]
    public IActionResult Predict([FromBody] TicketRequest request)
    {
        if (!classifierService.IsTrained)
            return BadRequest(new { error = "Model has not been trained yet. Call POST /api/ticketclassifier/train first." });

        var prediction = classifierService.Predict(request);
        return Ok(new
        {
            predictedCategory = prediction.Category,
            confidenceScores = prediction.Score
        });
    }
}

